export const JUGGLING_CHAOS_ORCHESTRATION_THEOREM_IDS = [
  'THM-JUGGLING-COMPOSITION-CORPUS-DETERMINISTIC',
  'THM-JUGGLING-COMPOSITION-VALIDITY-GATING',
  'THM-JUGGLING-COMPOSITION-FLOW-NOVELTY-TRADEOFF',
  'THM-JUGGLING-COMPOSITION-EVOLUTION-ELITIST-MONOTONE',
] as const;

export type JugglingChaosOrchestrationTheoremId =
  (typeof JUGGLING_CHAOS_ORCHESTRATION_THEOREM_IDS)[number];

